)

func TestKafkaInputTestNoPanicOnClientError(t *testing.T) {
    k := &kafkaInput{
        config: kafkaInputConfig{Hosts: []string{"127.0.0.1:1"}, Topics: []string{"topic-a"}},
        saramaConfig: sarama.NewConfig(),
    }

    defer func() {
        if r := recover(); r != nil {
            t.Fatalf("Test() panicked instead of returning an error: %v", r)
        }
    }()

    err := k.Test(input.TestContext{Logger: logp.NewLogger("kafka-repro")})
    require.Error(t, err)
}
